 1	import * as React from 'react';
 2	import { Tooltip, TooltipPosition } from '@patternfly/react-core';
 3	import { SVGIconProps } from '@patternfly/react-icons/dist/js/createIcon';
 4	import { serverConfig } from 'config/ServerConfig';
 5	import { icons } from 'config';
 6	import { KialiIcon } from '../../config/KialiIcon';
 7	import { infoStyle } from 'styles/IconStyle';
 8	
 9	type MissingSidecarProps = {
10	  className?: string;
11	  color?: string;
12	  dataTest?: string;
13	  icon?: React.ComponentClass<SVGIconProps>;
14	  meshtooltip?: string;
15	  text?: string;
16	  textmesh?: string;
17	  texttooltip?: string;
18	  tooltip?: boolean;
19	};
20	
21	export const MissingSidecar: React.FC<MissingSidecarProps> = ({
22	  textmesh = 'Out of mesh',
23	  text = 'Missing Sidecar',
24	  meshtooltip = 'Out of mesh. Istio sidecar container or Ambient labels not found in Pod(s). Check if the istio-injection label/annotation is correctly set on the namespace/workload.',
25	  texttooltip = 'Istio sidecar container not found in Pod(s). Check if the istio-injection label/annotation is correctly set on the namespace/workload.',
26	  tooltip = false,
27	  icon = icons.istio.missingSidecar.icon,
28	  color = icons.istio.missingSidecar.color,
29	  className,
30	  dataTest
31	}) => {
32	  const iconComponent = (
33	    <span className={className} data-test={dataTest}>
34	      {React.createElement(icon, { style: { color: color } })}
35	
36	      {!tooltip && (
37	        <span style={{ marginLeft: '0.5rem' }}>
38	          {serverConfig.ambientEnabled ? textmesh : text}
39	          <Tooltip
40	            key="tooltip_missing_sidecar"
41	            position={TooltipPosition.top}
42	            content={<div style={{ textAlign: 'left' }}>{serverConfig.ambientEnabled ? meshtooltip : texttooltip}</div>}
43	          >
44	            <KialiIcon.Info className={infoStyle} />
45	          </Tooltip>
46	        </span>
47	      )}
48	    </span>
49	  );
50	
51	  return tooltip ? (
52	    <Tooltip
53	      content={<div style={{ textAlign: 'left' }}>{serverConfig.ambientEnabled ? meshtooltip : texttooltip}</div>}
54	      position={TooltipPosition.right}
55	    >
56	      {iconComponent}
57	    </Tooltip>
58	  ) : (
59	    iconComponent
60	  );
61	};

